const connectWs = (jid) => {
  setJobId(jid);
  const ws = new WebSocket(`${process.env.NEXT_PUBLIC_WS_URL}/ws/job/${jid}?token=${token}`);
  ws.onmessage = (evt) => {
    const msg = JSON.parse(evt.data);
    setProgress(msg.progress);
    if (msg.phase) setCurrentPhase(msg.phase);
    setLogs((prev) => [...prev, `[${msg.phase || msg.status}] ${msg.log}`]);
    if (msg.progress === 100) {
      setDone(true);
      fetchBalance();
    }
  };
  ws.onerror = () => {
    // eslint-disable-next-line no-console
    console.warn('WebSocket 连接错误');
  };
  ws.onclose = (evt) => {
    if (evt.code === 4001) setError('WebSocket 鉴权失败');
  };
};

