26	 *   if bal < tonumber(ARGV[1]) then return -1 end
27	 *   return redis.call('DECRBY', KEYS[1], ARGV[1])
28	 *
29	 * @param {string} tenantId
30	 * @param {number} points - default COST_PER_JOB (10)
31	 * @returns {Promise<{ok: boolean, balance?: number, reason?: string}>}
32	 */
