34	  const client = getClient();
35	  const result = await client.eval(DEDUCT_LUA, 1, key(tenantId), points);
36	  if (Number(result) === -1) {
37	    return { ok: false, reason: 'INSUFFICIENT' };
38	  }
39	  return { ok: true, balance: Number(result) };
40	};
